import{_ as t,o as a,c as o,i as s}from"./chunks/framework.DP1yFSuu.js";const m=JSON.parse('{"title":"About Cobalt","description":"","frontmatter":{},"headers":[],"relativePath":"resources/about-cobalt.md","filePath":"resources/about-cobalt.md"}'),i={name:"resources/about-cobalt.md"};function n(r,e,l,c,d,h){return a(),o("div",null,[...e[0]||(e[0]=[s('<h1 id="about-cobalt" tabindex="-1">About Cobalt <a class="header-anchor" href="#about-cobalt" aria-label="Permalink to &quot;About Cobalt&quot;">​</a></h1><p>The name of the design system is inspired by the metallic element cobalt. Known for its extraordinary resilience and vivid blue hue, cobalt has shaped art and craftsmanship for millennia. These same qualities, durability and a timeless aesthetic, are core principles behind the Cobalt design system.</p><h2 id="built-to-endure" tabindex="-1">Built to endure <a class="header-anchor" href="#built-to-endure" aria-label="Permalink to &quot;Built to endure&quot;">​</a></h2><p>Cobalt superalloys withstand the extreme heat inside jet engine turbine blades. A design system faces a different kind of stress — scaling across teams, supporting enterprise-grade products, and edge cases — but the demand is the same: hold up under pressure without losing integrity.</p><h2 id="rooted-in-craft" tabindex="-1">Rooted in craft <a class="header-anchor" href="#rooted-in-craft" aria-label="Permalink to &quot;Rooted in craft&quot;">​</a></h2><p>Cobalt&#39;s signature blue pigment appears in Egyptian jewelry, the frescoes of Pompeii, and Chinese porcelain dating to the Tang Dynasty. Good design outlasts trends, and Cobalt is crafted with care and intetion to constuct thoughtful interfaces that stand the test of time.</p><h2 id="atomic-composition" tabindex="-1">Atomic composition <a class="header-anchor" href="#atomic-composition" aria-label="Permalink to &quot;Atomic composition&quot;">​</a></h2><p>At its core, Cobalt is composed of atomic building blocks—small, reusable components that combine to form complex user experiences. This composability makes the system flexible, scalable, and adaptable to a wide range of product needs.</p><h2 id="woven-into-the-system" tabindex="-1">Woven into the system <a class="header-anchor" href="#woven-into-the-system" aria-label="Permalink to &quot;Woven into the system&quot;">​</a></h2><p>Cobalt&#39;s periodic symbol, <code>Co</code>, namespaces every token and component. As a period-four element, it sits on the fourth row of the periodic table, and the number four echoes throughout the system: a 4 px base unit for spacing, as well as a four-level elevation scale. The result is a consistent rhythm that is easy to learn and easy to extend.</p>',10)])])}const b=t(i,[["render",n]]);export{m as __pageData,b as default};
